```go
// handler/order.go
func CreateOrderHandler(w http.ResponseWriter, r *http.Request) {
    var req struct{ Items []entity.OrderItem `json:"items"` }
    if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
        helpers.RespondError(w, http.StatusBadRequest, err)
        return
    }

    // 1️⃣ Handler → Usecase
    order, err := usecase.NewOrderUsecase().Create(r.Context(), req.Items)
    if err != nil {
        helpers.RespondError(w, http.StatusInternalServerError, err)
        return
    }

    // 2️⃣ Usecase → Repository
    // (внутри Create() вызывается repo.Create() → sqliteOrderRepo.Create())
    // 3️⃣ Repository → Entity
    // (sqliteOrderRepo.Create() получает уже заполненный entity.Order,
    //   а внутри Usecase перед этим вызывается order.CalculateTotal() и order.Validate())

    helpers.RespondJSON(w, http.StatusCreated, order)
}
```

