| **2** | `internal/usecase/order.go` | `import "beanbrew/internal/repository"`  <br> `import "beanbrew/internal/entity"` | ```go
type OrderUsecase struct{ repo repository.OrderRepository }

func NewOrderUsecase(r repository.OrderRepository) *OrderUsecase { return &OrderUsecase{repo: r} }

func (u *OrderUsecase) Create(ctx context.Context, items []entity.OrderItem) (*entity.Order, error) {
    o := &entity.Order{Items: items, Status: entity.StatusNew}
    if err := o.Validate(); err != nil { return nil, err }
    o.CalculateTotal()
    return o, u.repo.Create(o)
}

func (u *OrderUsecase) Cancel(ctx context.Context, id int) error {
    o, err := u.repo.GetByID(id)
    if err != nil { return err }
    if !o.CanCancel() { return entity.ErrInvalidTransition }
    return u.repo.UpdateStatus(id, entity.StatusCancelled)
}

func (u *OrderUsecase) Complete(ctx context.Context, id int) error {
    o, err := u.repo.GetByID(id)
    if err != nil { return err }
    if !o.CanComplete() { return entity.ErrInvalidTransition }
    return u.repo.UpdateStatus(id, entity.StatusCompleted)
}
``` | **Usecase‑слой** – бизнес‑логика: валидация, расчёт total, проверка переходов статуса, делегирование к репозиторию. |
